mapper.select:
SELECT DISTINCT s.id as schedule_id, p.name as project_name, s.venue, 
       s.date as schedule_date, s.time as schedule_time, s.status as schedule_status
FROM schedule s
LEFT JOIN project p ON s.project_id = p.id
WHERE s.status IN ('已结束', 'FINISHED', 'COMPLETED')
AND s.id NOT IN (
    SELECT DISTINCT schedule_id FROM result WHERE referee_id = #{refereeId}
)
AND s.id IN (
    SELECT DISTINCT schedule_id FROM registration WHERE status = 'APPROVED'
)
AND s.id NOT IN (
    SELECT DISTINCT schedule_id FROM referee_task WHERE referee_id = #{refereeId}
)
